43	
44	  // --- Multi-item policy & modifier scope ---
45	  it.todo("cursed sword + plain amulet (new customer, 1st contract) → 100+60 base, cursed adds 50 (of sword only), first-ins 10% of policy total → 160 + 50 + 16 + 5 = 231 G");
46	
47	  // --- Follow-up contract discount (15% on each contract after first) ---
48	  it.todo("second quote in scenario: cursed sword + plain amulet, 0 years → first ins still 10%, follow-up 15% off policy total");
