53	
54	  // --- Rounding in MHPCO's favor ---
55	  it.todo("premium calculation yielding 197.5 G → final premium 198 G (rounded up)");
56	
57	  // --- Claim: basic deductible & standard reimbursement ---
58	  it.todo("steel sword enchantment 3, damage 500 → payout 400 (500 - 100 deductible)");
59	  it.todo("damage to a rune (250 G), damage 200 → payout 100 (200 - 100 deductible)");
60	
61	  // --- Claim: high-enchantment 50% clause ---
62	  it.todo("steel sword enchantment 9, damage 1000 → payout 400 (50% then deductible: 500 - 100)");
63	
64	  // --- Claim: dragon material full reimbursement ---
65	  it.todo("dragon-material sword enchantment 5, damage 800 → payout 700 (full minus deductible)");
66	
67	  // --- Claim: dragon + high enchantment combined (50% wins) ---
68	  it.todo("dragon-material sword enchantment 8, damage 1000 → payout 400 (high-ench applies first then deductible)");
69	  it.todo("dragon-material sword enchantment 9, damage 1000 → payout 400 (50% rule wins, then deductible)");
70	
71	  // --- Claim: deductible per damage event ---
72	  it.todo("dragon attack damages insured sword 500 and amulet 300 → payout 600 (deductible applies once per damaged item)");
73	
74	  // --- Multiple items of same type ---
75	  it.todo("policy with two swords: insurance sum 2000 G, cap 4000 G; two sword damage entries each get own deductible");
76	  it.todo("claim with more sword damages than swords insured → CLI exits non-zero (claim rejected)");
77	
78	  // --- Cap exhaustion ---
79	  it.todo("sword + amulet policy → insurance sum 1600 G, cap 3200 G");
80	  it.todo("cursed sword cap is 2000 G (based on unmodified insurance value, premium modifiers do not raise cap)");
81	  it.todo("sword + 3 runes block: insurance sum 1750 G (block discount affects premium only, not insurance sum)");
82	  it.todo("sword (cap 2000): claim 1500 → payout 1400, remainingCap 600; second claim 1500 → payout 600, remainingCap 0");
83	
84	  // --- Rounding payout ---
85	  it.todo("payout calculation yielding 350.5 G → final payout 350 G (rounded down)");
86	
87	  // --- Error cases ---
88	  it.todo("quote with unknown item type (e.g. broomstick) → CLI exits non-zero with error to stderr");
89	  it.todo("claim references damage entry whose item is not in policy → CLI exits non-zero");
90	  it.todo("claim contains damage entry with negative amount → CLI exits non-zero");
