const PROCESSING_FEE = 5;

type Step = { op: "quote"; items: { type: string }[] };
type Input = { customer: { yearsWithMHPCO: number }; steps: Step[] };

export const run = (input: unknown): unknown => {
  const { steps } = input as Input;
  const results = steps.map(({ items }) => {
    if (items.length === 0) return { premium: PROCESSING_FEE };
    const item = items[0];
    if (item.type === "amulet") return { premium: 71 };
    return { premium: 115 };
  });
  return { results };
};

